package com.hospital.management.util;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;class PrescriptionStatusTransitionTest {@Test void activeTransitions(){assertEquals("COMPLETED",PrescriptionStatusTransition.target("ACTIVE","complete").orElseThrow());assertEquals("CANCELLED",PrescriptionStatusTransition.target("ACTIVE","cancel").orElseThrow());}@Test void terminalBlocked(){assertTrue(PrescriptionStatusTransition.target("COMPLETED","cancel").isEmpty());assertTrue(PrescriptionStatusTransition.target("CANCELLED","complete").isEmpty());}@Test void invalidAction(){assertTrue(PrescriptionStatusTransition.target("ACTIVE","reactivate").isEmpty());}}
